    it.todo("should add 5G processing fee to every premium");
    it.todo("should round all amounts to whole G in MHPCO's favor (ceiling)");
  });

  describe("Processing a claim", () => {
    it.todo("should pay out damage minus 100G deductible");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should reimburse at 50% for items with enchantment level >= 8");
